patch:
diff --git a/llvm/lib/Analysis/ConstantFolding.cpp b/llvm/lib/Analysis/ConstantFolding.cpp
index a7a6de3f3b97..4f678edc1da0 100644
--- a/llvm/lib/Analysis/ConstantFolding.cpp
+++ b/llvm/lib/Analysis/ConstantFolding.cpp
@@ -1463,8 +1463,11 @@ Constant *llvm::ConstantFoldCastOperand(unsigned Opcode, Constant *C,
     return FoldBitCast(C, DestTy, DL);
   }

-  if (ConstantExpr::isDesirableCastOp(Opcode))
+  if (ConstantExpr::isDesirableCastOp(Opcode) &&
+      CastInst::castIsValid(Instruction::CastOps(Opcode), C, DestTy))
+    {
     return ConstantExpr::getCast(Opcode, C, DestTy);
+  }
   return ConstantFoldCastInstruction(Opcode, C, DestTy);
 }

